 70→  document.body.addEventListener("htmx:afterSettle", function () {
 71→    if (pendingDeleteSwap) {
 72→      pendingDeleteSwap = false;
 73→      updateEmptyState();
 74→    }
 75→
 76→    if (!pendingFocusTarget) {
 77→      return;
 78→    }
 79→
 80→    var pending = pendingFocusTarget;
 81→    pendingFocusTarget = null;
 82→
 83→    var el;
 84→    if (pending.type === "element") {
 85→      el = pending.el;
 86→    } else if (pending.type === "selector") {
 87→      el = document.querySelector(pending.selector);
 88→    }
 89→
 90→    if (!el) {
 91→      return;
 92→    }
 93→
 94→    // Make the target focusable if it isn't already
 95→    if (!el.hasAttribute("tabindex") && el.tagName !== "INPUT" && el.tagName !== "BUTTON" && el.tagName !== "A") {
 96→      el.setAttribute("tabindex", "-1");
 97→    }
