  1→use askama::Template;
  2→use axum::extract::{Path, State};
  3→use axum::http::{HeaderMap, StatusCode};
  4→use axum::response::{Html, IntoResponse, Redirect, Response};
  5→use axum::Form;
  6→use sqlx::PgPool;
  7→use uuid::Uuid;
  8→
  9→use super::auth::AuthenticatedUser;
 10→use super::{htmx_response_with_announce, is_htmx_request};
 11→use crate::domain::{TodoTitleError, WaitingForId, WaitingOnPersonError};
 12→use crate::services::inbox_service;
 13→use crate::services::waiting_for_service::{
 14→    self, AddWaitingForError, CompleteWaitingForError, DeleteWaitingForError, UpdateWaitingForError,
 15→};
 16→
 17→pub struct WaitingForView {
 18→    pub id: String,
 19→    pub title: String,
 20→    pub waiting_on: String,
 21→    pub date_added: String,
 22→}
 23→
 24→#[derive(Template)]
 25→#[template(path = "waiting_for.html")]
 26→struct WaitingForTemplate {
 27→    current_page: &'static str,
 28→    inbox_count: i64,
 29→    items: Vec<WaitingForView>,
 30→    error_message: Option<String>,
 31→}
 32→
 33→#[derive(Template)]
 34→#[template(path = "waiting_for_item.html")]
 35→struct WaitingForItemTemplate {
 36→    item: WaitingForView,
 37→}
 38→
 39→#[derive(Template)]
 40→#[template(path = "waiting_for_edit.html")]
 41→struct WaitingForEditTemplate {
 42→    item: WaitingForView,
 43→}
 44→
 45→fn build_view(item: &crate::domain::WaitingForItem) -> WaitingForView {
 46→    WaitingForView {
 47→        id: item.id().as_uuid().to_string(),
 48→        title: item.title().as_str().to_string(),
 49→        waiting_on: item.waiting_on().as_str().to_string(),
 50→        date_added: item.created_at().format("%b %d, %Y").to_string(),
 51→    }
 52→}
 53→
 54→pub async fn get_waiting_for(
 55→    AuthenticatedUser(user_id): AuthenticatedUser,
 56→    State(pool): State<PgPool>,
 57→) -> Result<Response, WaitingForError> {
 58→    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
 59→        .await
 60→        .map_err(WaitingForError::Unexpected)?;
 61→
 62→    let items = waiting_for_service::list_active_waiting_for_items(&pool, &user_id)
 63→        .await
 64→        .map_err(WaitingForError::Unexpected)?;
 65→
 66→    let item_views: Vec<WaitingForView> = items.iter().map(build_view).collect();
 67→
 68→    let template = WaitingForTemplate {
 69→        current_page: "waiting_for",
 70→        inbox_count,
 71→        items: item_views,
 72→        error_message: None,
 73→    };
 74→    Ok(Html(template.render()?).into_response())
 75→}
 76→
 77→#[derive(serde::Deserialize)]
 78→pub struct AddWaitingForForm {
 79→    pub title: String,
 80→    pub waiting_on: String,
 81→}
 82→
 83→pub async fn post_waiting_for(
 84→    AuthenticatedUser(user_id): AuthenticatedUser,
 85→    State(pool): State<PgPool>,
 86→    headers: HeaderMap,
 87→    Form(form): Form<AddWaitingForForm>,
 88→) -> Result<Response, WaitingForError> {
 89→    let htmx = is_htmx_request(&headers);
 90→
 91→    if form.title.trim().is_empty() {
 92→        if htmx {
 93→            return Ok(StatusCode::NO_CONTENT.into_response());
 94→        }
 95→        return Ok(Redirect::to("/waiting-for").into_response());
 96→    }
 97→
 98→    if form.waiting_on.trim().is_empty() {
 99→        if htmx {
100→            return Ok(StatusCode::NO_CONTENT.into_response());
101→        }
102→        return Ok(Redirect::to("/waiting-for").into_response());
103→    }
104→
105→    match waiting_for_service::add_waiting_for_item(
106→        &pool,
107→        user_id.clone(),
108→        form.title,
109→        form.waiting_on,
110→    )
111→    .await
112→    {
113→        Ok(item) => {
114→            if htmx {
115→                let template = WaitingForItemTemplate {
116→                    item: build_view(&item),
117→                };
118→                let body = template.render().map_err(WaitingForError::Render)?;
119→                Ok(htmx_response_with_announce(
120→                    Html(body),
121→                    "Waiting-for item added",
122→                ))
123→            } else {
124→                Ok(Redirect::to("/waiting-for").into_response())
125→            }
126→        }
127→        Err(AddWaitingForError::InvalidTitle(title_err)) => {
128→            let user_facing = match title_err {
129→                TodoTitleError::Empty => {
130→                    if htmx {
131→                        return Ok(StatusCode::NO_CONTENT.into_response());
132→                    }
133→                    return Ok(Redirect::to("/waiting-for").into_response());
134→                }
135→                TodoTitleError::TooLong { max, .. } => {
136→                    format!("That title is too long (max {max} characters)")
137→                }
138→            };
139→            render_waiting_for_with_error(&pool, &user_id, &user_facing).await
140→        }
141→        Err(AddWaitingForError::InvalidWaitingOn(person_err)) => {
142→            let user_facing = match person_err {
143→                WaitingOnPersonError::Empty => {
144→                    if htmx {
145→                        return Ok(StatusCode::NO_CONTENT.into_response());
146→                    }
147→                    return Ok(Redirect::to("/waiting-for").into_response());
148→                }
149→                WaitingOnPersonError::TooLong { max, .. } => {
150→                    format!("That name is too long (max {max} characters)")
151→                }
152→            };
153→            render_waiting_for_with_error(&pool, &user_id, &user_facing).await
154→        }
155→        Err(AddWaitingForError::Unexpected(err)) => Err(WaitingForError::Unexpected(err)),
156→    }
157→}
158→
159→async fn render_waiting_for_with_error(
160→    pool: &PgPool,
161→    user_id: &crate::domain::UserId,
162→    error_message: &str,
163→) -> Result<Response, WaitingForError> {
164→    let inbox_count = inbox_service::get_inbox_count(pool, user_id)
165→        .await
166→        .map_err(WaitingForError::Unexpected)?;
167→
168→    let items = waiting_for_service::list_active_waiting_for_items(pool, user_id)
169→        .await
170→        .map_err(WaitingForError::Unexpected)?;
171→
172→    let item_views: Vec<WaitingForView> = items.iter().map(build_view).collect();
173→
174→    let template = WaitingForTemplate {
175→        current_page: "waiting_for",
176→        inbox_count,
177→        items: item_views,
178→        error_message: Some(error_message.to_string()),
179→    };
180→    let body = template.render().map_err(WaitingForError::Render)?;
181→    Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
182→}
183→
184→pub async fn post_complete_waiting_for(
185→    AuthenticatedUser(user_id): AuthenticatedUser,
186→    State(pool): State<PgPool>,
187→    headers: HeaderMap,
188→    Path(item_id): Path<Uuid>,
189→) -> Result<Response, WaitingForError> {
190→    let htmx = is_htmx_request(&headers);
191→    let wf_id = WaitingForId::from_uuid(item_id);
192→
193→    match waiting_for_service::complete_waiting_for_item(&pool, &wf_id, &user_id).await {
194→        Ok(()) => {
195→            if htmx {
196→                Ok(htmx_response_with_announce(
197→                    Html(String::new()),
198→                    "Item received",
199→                ))
200→            } else {
201→                Ok(Redirect::to("/waiting-for").into_response())
202→            }
203→        }
204→        Err(CompleteWaitingForError::NotFound) => Ok((
205→            StatusCode::NOT_FOUND,
206→            Html("<h1>Waiting-for item not found</h1>".to_string()),
207→        )
208→            .into_response()),
209→        Err(CompleteWaitingForError::Unauthorized) => Ok((
210→            StatusCode::FORBIDDEN,
211→            Html("<h1>Not authorized</h1>".to_string()),
212→        )
213→            .into_response()),
214→        Err(CompleteWaitingForError::Unexpected(err)) => Err(WaitingForError::Unexpected(err)),
215→    }
216→}
