241→        )
242→            .into_response()),
243→        Err(DeleteWaitingForError::Unauthorized) => Ok((
244→            StatusCode::FORBIDDEN,
245→            Html("<h1>Not authorized</h1>".to_string()),
246→        )
247→            .into_response()),
248→        Err(DeleteWaitingForError::Unexpected(err)) => Err(WaitingForError::Unexpected(err)),
