250→}
251→
252→pub async fn get_edit_waiting_for(
253→    AuthenticatedUser(user_id): AuthenticatedUser,
254→    State(pool): State<PgPool>,
255→    headers: HeaderMap,
256→    Path(item_id): Path<Uuid>,
257→) -> Result<Response, WaitingForError> {
258→    let wf_id = WaitingForId::from_uuid(item_id);
259→    let item =
260→        crate::infrastructure::waiting_for_repository::find_waiting_for_item_by_id(&pool, &wf_id)
261→            .await
262→            .map_err(|e| WaitingForError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
263→            .ok_or_else(|| WaitingForError::Unexpected(anyhow::anyhow!("Item not found")))?;
264→
265→    if item.user_id() != &user_id {
266→        return Ok((
267→            StatusCode::FORBIDDEN,
268→            Html("<h1>Not authorized</h1>".to_string()),
269→        )
270→            .into_response());
271→    }
272→
273→    let htmx = is_htmx_request(&headers);
274→
275→    if htmx {
276→        let template = WaitingForEditTemplate {
277→            item: build_view(&item),
278→        };
279→        let body = template.render().map_err(WaitingForError::Render)?;
280→        Ok(Html(body).into_response())
281→    } else {
282→        Ok(Redirect::to("/waiting-for").into_response())
283→    }
284→}
