354→            let user_facing = match person_err {
355→                WaitingOnPersonError::Empty => "Who or what cannot be empty".to_string(),
356→                WaitingOnPersonError::TooLong { max, .. } => {
357→                    format!("That name is too long (max {max} characters)")
358→                }
359→            };
360→            render_waiting_for_with_error(&pool, &user_id, &user_facing).await
